#include <stdio.h>
#include <stdlib.h>

long long factorial(int n) {
    long long result = 1;
    for (int i = 2; i <= n; i++) {
        result = (result * i);
    }
    return result;
}

long long binomial_coefficient(int n, int k) {
    long long result = factorial(n);
    result = (result / factorial(k)) / factorial(n - k);
    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, R;
        scanf("%d %d", &n, &R);
        int found = 0;
        for (int K = 0; K <= 2 * n - 1; K++) {
            long long result = binomial_coefficient(2 * n - 1, K);
            if (result % (2 * n) == R) {
                printf("%d\n", K);
                found = 1;
                break;
            }
        }
        if (!found) {
            printf("-1\n");
        }
    }
    return 0;
}

